import React, { useRef, useMemo, useState, useEffect } from 'react';
import { Transaction } from '../../types';
import { 
    IndianRupee, Check, HelpCircle, Loader2, ArrowDownLeft, ArrowUpRight, Gauge
} from 'lucide-react';
import { CATEGORY_CONFIG } from './categories';

interface TransactionListProps {
    transactions: Transaction[];
    onDelete: (id: string) => void;
    onEdit: (t: Transaction) => void;
    onView: (t: Transaction) => void;

    // Selection Props
    isSelectionMode?: boolean;
    selectedIds?: Set<string>;
    onToggleSelection?: (id: string) => void;
    onLongPress?: (id: string) => void;
}

const CategoryIcon: React.FC<{ categoryId: string, type: string, className?: string }> = ({ categoryId, type, className }) => {
    // Lookup the icon from our central config
    const configList = CATEGORY_CONFIG[type as keyof typeof CATEGORY_CONFIG] || CATEGORY_CONFIG.expense;
    const categoryData = configList.find(c => c.id === categoryId);

    if (categoryData) {
        const IconComponent = categoryData.icon;
        return <IconComponent className={className} />;
    }

    // Fallback for custom categories
    return <HelpCircle className={className} />;
}

const TransactionList: React.FC<TransactionListProps> = ({ 
    transactions, 
    onView,
    isSelectionMode,
    selectedIds,
    onToggleSelection,
    onLongPress
}) => {
    // Optimization 1: Memoize grouping logic to prevent heavy calculation on every render
    const grouped = useMemo(() => {
        return transactions.reduce((acc, t) => {
            const date = new Date(t.transaction_date).toDateString();
            if (!acc[date]) acc[date] = [];
            acc[date].push(t);
            return acc;
        }, {} as Record<string, Transaction[]>);
    }, [transactions]);

    // Optimization 2: Lazy Loading State
    const [displayLimit, setDisplayLimit] = useState(15); // Initial number of days/groups to show
    const observerTarget = useRef<HTMLDivElement>(null);

    const dateKeys = useMemo(() => Object.keys(grouped), [grouped]);
    const visibleKeys = dateKeys.slice(0, displayLimit);
    const hasMore = displayLimit < dateKeys.length;

    // Reset pagination when filters change (transactions prop changes)
    useEffect(() => {
        setDisplayLimit(15);
    }, [transactions]);

    // Optimization 3: Intersection Observer for Infinite Scroll
    useEffect(() => {
        const observer = new IntersectionObserver(
            (entries) => {
                if (entries[0].isIntersecting && hasMore) {
                    setDisplayLimit((prev) => prev + 10); // Load 10 more days at a time
                }
            },
            { threshold: 0.1, rootMargin: '200px' } // Load before reaching exact bottom
        );

        if (observerTarget.current) {
            observer.observe(observerTarget.current);
        }

        return () => observer.disconnect();
    }, [hasMore, dateKeys.length]);

    // Refs for Long Press Logic
    const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    const isLongPressTriggered = useRef(false);

    const handlePointerDown = (id: string) => {
        if (isSelectionMode) return; 

        isLongPressTriggered.current = false;
        timerRef.current = setTimeout(() => {
            isLongPressTriggered.current = true;
            if (onLongPress) onLongPress(id);
        }, 500); 
    };

    const handlePointerUp = () => {
        if (timerRef.current) {
            clearTimeout(timerRef.current);
            timerRef.current = null;
        }
    };

    const handleClick = (t: Transaction) => {
        if (isLongPressTriggered.current) {
            isLongPressTriggered.current = false;
            return;
        }
        if (isSelectionMode && onToggleSelection) {
            onToggleSelection(t.id);
        } else {
            onView(t);
        }
    };

    if (transactions.length === 0) {
        return (
            <div className="flex flex-col items-center justify-center py-20 opacity-50">
                <div className="p-6 bg-gray-100 dark:bg-gray-800 rounded-full mb-4">
                    <IndianRupee className="w-10 h-10 text-gray-400" />
                </div>
                <p className="text-gray-500 dark:text-gray-400 font-medium">No transactions found.</p>
            </div>
        );
    }

    return (
        <div className="space-y-8 select-none">
            {visibleKeys.map(dateStr => {
                const dayTransactions = grouped[dateStr];

                // Calculate daily totals
                const dailyIncome = dayTransactions
                    .filter(t => t.type === 'income')
                    .reduce((sum, t) => sum + Number(t.amount), 0);

                const dailyExpense = dayTransactions
                    .filter(t => t.type === 'expense')
                    .reduce((sum, t) => sum + Number(t.amount), 0);

                const dailyBalance = dailyIncome - dailyExpense;

                return (
                    <div key={dateStr} className="animate-fade-in-up">
                        {/* Enhanced Date Header with Verdict */}
                        <div className="sticky top-0 z-10 bg-[#F9F6F2]/95 dark:bg-[#0D1117]/95 backdrop-blur-sm shadow-sm py-2.5 mb-2 px-2 flex justify-between items-center border-b border-gray-200 dark:border-gray-800 transition-colors rounded-xl mx-[-4px]">
                            <h3 className="font-bold text-gray-600 dark:text-gray-300 text-xs uppercase tracking-widest pl-1">
                                {new Date(dateStr).toLocaleDateString(undefined, { weekday: 'short', day: 'numeric', month: 'short' })}
                            </h3>

                            <div className="flex items-center gap-3">
                                {/* Income Summary */}
                                {dailyIncome > 0 && (
                                    <div className="flex items-center text-[10px] font-bold text-emerald-600 dark:text-emerald-400">
                                        <ArrowDownLeft className="w-3 h-3 mr-0.5" />
                                        <span>{dailyIncome.toLocaleString('en-IN', { maximumFractionDigits: 0 })}</span>
                                    </div>
                                )}

                                {/* Expense Summary */}
                                {dailyExpense > 0 && (
                                    <div className="flex items-center text-[10px] font-bold text-rose-600 dark:text-rose-400">
                                        <ArrowUpRight className="w-3 h-3 mr-0.5" />
                                        <span>{dailyExpense.toLocaleString('en-IN', { maximumFractionDigits: 0 })}</span>
                                    </div>
                                )}

                                {/* Verdict Pill */}
                                <div className={`px-2 py-0.5 rounded-md text-[10px] font-bold tabular-nums border ${
                                    dailyBalance >= 0 
                                        ? 'bg-emerald-100 dark:bg-emerald-900/30 text-emerald-700 dark:text-emerald-300 border-emerald-200 dark:border-emerald-800' 
                                        : 'bg-rose-100 dark:bg-rose-900/30 text-rose-700 dark:text-rose-300 border-rose-200 dark:border-rose-800'
                                }`}>
                                    {dailyBalance >= 0 ? '+' : ''}{dailyBalance.toLocaleString('en-IN', { maximumFractionDigits: 0 })}
                                </div>
                            </div>
                        </div>

                        <div className="flex flex-col gap-3">
                            {dayTransactions.map((t) => {
                                const isIncome = t.type === 'income';
                                const isExpense = t.type === 'expense';
                                const isSelected = selectedIds?.has(t.id);
                                const mileage = t.metadata?.mileage;

                                return (
                                    <div
                                        key={t.id}
                                        onPointerDown={() => handlePointerDown(t.id)}
                                        onPointerUp={handlePointerUp}
                                        onPointerLeave={handlePointerUp}
                                        onPointerCancel={handlePointerUp}
                                        onClick={() => handleClick(t)}
                                        className={`group relative flex items-center justify-between p-4 rounded-2xl border transition-all duration-200 text-left active:scale-[0.99] cursor-pointer
                                            ${isSelected 
                                                ? 'bg-indigo-50 dark:bg-indigo-900/20 border-indigo-500 shadow-md scale-[0.99]' 
                                                : 'bg-white dark:bg-[#1e1f22] border-gray-100 dark:border-gray-800 hover:border-gray-300 dark:hover:border-gray-600 shadow-sm hover:shadow-lg'
                                            }
                                        `}
                                    >
                                        <div className="flex items-center gap-4 min-w-0 flex-1">
                                            {/* Icon or Checkbox */}
                                            <div className={`w-12 h-12 rounded-xl flex items-center justify-center flex-shrink-0 transition-transform ${isSelectionMode ? '' : 'group-hover:scale-105'} 
                                                ${isSelected ? 'bg-indigo-500 text-white' : 
                                                    isIncome ? 'bg-emerald-100 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400' :
                                                    isExpense ? 'bg-rose-100 dark:bg-rose-900/30 text-rose-600 dark:text-rose-400' :
                                                    'bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400'
                                                }`}>
                                                {isSelectionMode ? (
                                                    isSelected ? <Check className="w-6 h-6" /> : <div className="w-5 h-5 rounded-full border-2 border-gray-400 dark:border-gray-600" />
                                                ) : (
                                                    <CategoryIcon categoryId={t.category} type={t.type} className="w-5 h-5" />
                                                )}
                                            </div>

                                            <div className="min-w-0 flex flex-col gap-0.5 flex-1 pr-2">
                                                <div className="flex items-center gap-2">
                                                    <p className={`font-bold truncate text-base leading-tight ${isSelected ? 'text-indigo-900 dark:text-indigo-100' : 'text-gray-900 dark:text-white'}`}>
                                                        {t.description}
                                                    </p>
                                                    {mileage && (
                                                        <span className="text-[10px] font-bold bg-gray-100 dark:bg-white/10 px-1.5 py-0.5 rounded flex items-center gap-1 text-gray-600 dark:text-gray-300">
                                                            <Gauge className="w-3 h-3" /> {mileage} km/L
                                                        </span>
                                                    )}
                                                </div>
                                                <div className="flex items-center gap-2 text-xs font-medium text-gray-500 dark:text-gray-400">
                                                    <span className="capitalize truncate">{t.category}</span>
                                                    <span className="w-1 h-1 bg-gray-300 dark:bg-gray-600 rounded-full flex-shrink-0"></span>
                                                    <span className="opacity-70 truncate">{t.payment_method}</span>
                                                </div>
                                            </div>
                                        </div>

                                        <div className="flex flex-col items-end gap-0.5 pl-1 flex-shrink-0">
                                            <span className={`text-base font-bold tabular-nums whitespace-nowrap flex-shrink-0 ${
                                                isIncome ? 'text-emerald-600 dark:text-emerald-400' : 
                                                isExpense ? 'text-red-600 dark:text-red-400' : 
                                                'text-indigo-600 dark:text-indigo-400'
                                            }`}>
                                                {isExpense ? '-' : '+'}₹{Number(t.amount).toLocaleString('en-IN')}
                                            </span>
                                            <span className="text-[10px] font-medium text-gray-400 dark:text-gray-600">
                                                {new Date(t.transaction_date).toLocaleTimeString(undefined, {hour: 'numeric', minute:'2-digit', hour12: true})}
                                            </span>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                );
            })}

            {/* Sentinel for Infinite Scroll */}
            {hasMore && (
                <div ref={observerTarget} className="py-6 flex justify-center items-center">
                    <div className="flex items-center gap-2 text-gray-400 dark:text-gray-500 text-xs font-medium bg-gray-100 dark:bg-gray-800 px-4 py-2 rounded-full">
                        <Loader2 className="w-3 h-3 animate-spin" />
                        Loading more history...
                    </div>
                </div>
            )}
        </div>
    );
};

export default TransactionList;

import React, { useMemo, useState, useRef, useEffect } from 'react';
import { Transaction } from '../../types';
import { 
    ArrowLeft, Edit2, Trash2, Copy, Calendar, Clock, 
    CreditCard, ArrowUpRight, ArrowDownLeft, 
    ArrowRightLeft, Receipt, CheckCircle2, Wallet, MapPin, ExternalLink,
    Layers, Plus, Minus, Crosshair, Globe, Navigation,
    Car, Gauge, Droplets, Route, Fuel
} from 'lucide-react';
import DescriptionModal from './DescriptionModal';

// Declare Leaflet for the preview map
declare const L: any;

interface TransactionDetailPageProps {
    transaction: Transaction;
    onBack: () => void;
    onEdit: (t: Transaction) => void;
    onDelete: (id: string) => void;
    onDuplicate: (t: Transaction) => void;
}

const InfoCard: React.FC<{ label: string, value: string, subValue?: string, icon: React.ElementType, className?: string }> = ({ label, value, subValue, icon: Icon, className }) => (
    <div className={`bg-white dark:bg-[#1e1f22] p-4 rounded-2xl border border-gray-100 dark:border-gray-800 shadow-sm flex flex-col justify-between h-full ${className}`}>
        <div className="flex items-center gap-2 mb-2 text-gray-400 dark:text-gray-500">
            <Icon className="w-4 h-4" />
            <span className="text-[10px] font-bold uppercase tracking-wider">{label}</span>
        </div>
        <div>
            <p className="text-sm font-bold text-gray-900 dark:text-white truncate">{value}</p>
            {subValue && <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">{subValue}</p>}
        </div>
    </div>
);

const TransactionDetailPage: React.FC<TransactionDetailPageProps> = ({ 
    transaction, 
    onBack, 
    onEdit, 
    onDelete, 
    onDuplicate 
}) => {
    const [isDescriptionModalOpen, setIsDescriptionModalOpen] = useState(false);
    const mapPreviewRef = useRef<HTMLDivElement>(null);
    const mapInstanceRef = useRef<any>(null);
    const tileLayerRef = useRef<any>(null);

    // Map State
    const [mapLayer, setMapLayer] = useState<'standard' | 'satellite' | 'dark'>('standard');
    const [isLayerMenuOpen, setIsLayerMenuOpen] = useState(false);

    // Initialize preview map
    useEffect(() => {
        if (!transaction.location || !mapPreviewRef.current) return;

        if (mapInstanceRef.current) {
            mapInstanceRef.current.remove();
        }

        const map = L.map(mapPreviewRef.current, {
            zoomControl: false,
            dragging: true, // Allow panning
            touchZoom: true,
            doubleClickZoom: true,
            scrollWheelZoom: false, // Prevent page scroll blocking
            boxZoom: false,
            keyboard: false,
            attributionControl: false
        }).setView([transaction.location.lat, transaction.location.lng], 16);

        mapInstanceRef.current = map;

        // Add initial marker
        const customIcon = L.divIcon({
            className: 'custom-map-marker',
            html: `<div style="
                width: 32px; 
                height: 32px; 
                background-color: #ef4444; 
                border-radius: 50% 50% 50% 0;
                transform: rotate(-45deg);
                border: 3px solid white; 
                box-shadow: 0 4px 6px rgba(0,0,0,0.3);
                display: flex; 
                align-items: center; 
                justify-content: center;
                color: white;
            ">
                <div style="width: 10px; height: 10px; background: white; border-radius: 50%;"></div>
            </div>`,
            iconSize: [32, 32],
            iconAnchor: [16, 32], // Tip of teardrop
        });

        L.marker([transaction.location.lat, transaction.location.lng], { icon: customIcon }).addTo(map);

        // Initial Layer
        updateTileLayer(map, 'standard');

        return () => {
            if (mapInstanceRef.current) {
                mapInstanceRef.current.remove();
                mapInstanceRef.current = null;
            }
        };
    }, [transaction.location]);

    const updateTileLayer = (map: any, layerType: 'standard' | 'satellite' | 'dark') => {
        if (tileLayerRef.current) {
            map.removeLayer(tileLayerRef.current);
        }

        let url = '';
        switch (layerType) {
            case 'satellite':
                url = 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}';
                break;
            case 'dark':
                url = 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png';
                break;
            case 'standard':
            default:
                url = 'https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png';
                break;
        }

        tileLayerRef.current = L.tileLayer(url, { maxZoom: 19 }).addTo(map);
    };

    const handleLayerChange = (type: 'standard' | 'satellite' | 'dark') => {
        setMapLayer(type);
        if (mapInstanceRef.current) {
            updateTileLayer(mapInstanceRef.current, type);
        }
        setIsLayerMenuOpen(false);
    };

    const handleZoom = (dir: 'in' | 'out') => {
        if (!mapInstanceRef.current) return;
        if (dir === 'in') mapInstanceRef.current.zoomIn();
        else mapInstanceRef.current.zoomOut();
    };

    const handleRecenter = () => {
        if (mapInstanceRef.current && transaction.location) {
            mapInstanceRef.current.flyTo([transaction.location.lat, transaction.location.lng], 16, { duration: 1 });
        }
    };

    const theme = useMemo(() => {
        if (transaction.type === 'income') return {
            text: 'text-emerald-600 dark:text-emerald-400',
            bg: 'bg-emerald-100 dark:bg-emerald-900/30',
            glow: 'from-emerald-500/20 to-teal-500/20',
            icon: ArrowDownLeft,
            label: 'Income'
        };
        if (transaction.type === 'expense') return {
            text: 'text-rose-600 dark:text-rose-400',
            bg: 'bg-rose-100 dark:bg-rose-900/30',
            glow: 'from-rose-500/20 to-orange-500/20',
            icon: ArrowUpRight,
            label: 'Expense'
        };
        return {
            text: 'text-indigo-600 dark:text-indigo-400',
            bg: 'bg-indigo-100 dark:bg-indigo-900/30',
            glow: 'from-indigo-500/20 to-purple-500/20',
            icon: ArrowRightLeft,
            label: 'Transfer'
        };
    }, [transaction.type]);

    const dateObj = new Date(transaction.transaction_date);
    const dateStr = dateObj.toLocaleDateString(undefined, { month: 'long', day: 'numeric', year: 'numeric' });
    const weekdayStr = dateObj.toLocaleDateString(undefined, { weekday: 'long' });
    const timeStr = dateObj.toLocaleTimeString(undefined, { hour: 'numeric', minute: '2-digit', hour12: true });

    // Calculate time ago
    const timeAgo = useMemo(() => {
        const diff = (new Date().getTime() - dateObj.getTime()) / 1000;
        if (diff < 60) return 'Just now';
        if (diff < 3600) return `${Math.floor(diff / 60)} mins ago`;
        if (diff < 86400) return `${Math.floor(diff / 3600)} hours ago`;
        return `${Math.floor(diff / 86400)} days ago`;
