    const handleEditClick = (v: Vehicle) => {
        setEditingId(v.id);
        setName(v.name);
        setType(v.type);
        setPlate(v.number_plate);
        setOdometer(v.current_odometer.toString());
        setIsFormOpen(true);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
