        const vehicleData = {
            name,
            type,
            number_plate: plate,
            current_odometer: parseFloat(odometer) || 0
        };

        if (editingId) {
            // Update existing
            const vehicleToUpdate = vehicles.find(v => v.id === editingId);
            if (vehicleToUpdate) {
                await onUpdateVehicle({
                    ...vehicleToUpdate,
                    ...vehicleData
                });
            }
        } else {
            // Add new
            await onAddVehicle(vehicleData);
