                                    </div>

                                    <button 
                                        type="submit" 
                                        className="w-full py-3 bg-red-600 hover:bg-red-700 text-white rounded-xl font-bold text-sm shadow-lg shadow-red-500/20 transition-all active:scale-[0.98] flex items-center justify-center gap-2 mt-2"
