import React, { useEffect, useRef, useState } from 'react';
import { X, Layers, Plus, Minus, Crosshair, MapPin, Globe, ExternalLink, Navigation } from 'lucide-react';
import { TransactionLocation } from '../../types';

// Declare Leaflet
declare const L: any;

interface FullScreenMapModalProps {
    isOpen: boolean;
    onClose: () => void;
    location: TransactionLocation;
}

const FullScreenMapModal: React.FC<FullScreenMapModalProps> = ({ isOpen, onClose, location }) => {
    const mapContainerRef = useRef<HTMLDivElement>(null);
    const mapInstanceRef = useRef<any>(null);
    const tileLayerRef = useRef<any>(null);
    const [mapLayer, setMapLayer] = useState<'standard' | 'satellite' | 'dark'>('standard');
    const [isLayerMenuOpen, setIsLayerMenuOpen] = useState(false);

    useEffect(() => {
        if (!isOpen || !mapContainerRef.current) return;

        // Cleanup previous instance
        if (mapInstanceRef.current) {
            mapInstanceRef.current.remove();
            mapInstanceRef.current = null;
        }

        const map = L.map(mapContainerRef.current, {
            zoomControl: false,
            attributionControl: false
        }).setView([location.lat, location.lng], 16);

        mapInstanceRef.current = map;

        // Add Marker
        const customIcon = L.divIcon({
            className: 'custom-map-marker',
            html: `<div style="
                width: 40px; 
                height: 40px; 
                background-color: #ef4444; 
                border-radius: 50% 50% 50% 0;
                transform: rotate(-45deg);
                border: 3px solid white; 
                box-shadow: 0 4px 6px rgba(0,0,0,0.3);
                display: flex; 
                align-items: center; 
                justify-content: center;
                color: white;
            ">
                <div style="width: 12px; height: 12px; background: white; border-radius: 50%;"></div>
            </div>`,
            iconSize: [40, 40],
            iconAnchor: [20, 40],
        });

        L.marker([location.lat, location.lng], { icon: customIcon }).addTo(map);

        updateTileLayer(map, mapLayer);

        return () => {
            if (mapInstanceRef.current) {
                mapInstanceRef.current.remove();
                mapInstanceRef.current = null;
            }
        };
    }, [isOpen, location]);

    const updateTileLayer = (map: any, layerType: 'standard' | 'satellite' | 'dark') => {
        if (tileLayerRef.current) {
            map.removeLayer(tileLayerRef.current);
        }

        let url = '';
        switch (layerType) {
            case 'satellite':
                url = 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}';
                break;
            case 'dark':
                url = 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png';
                break;
            case 'standard':
            default:
                url = 'https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png';
                break;
        }

        tileLayerRef.current = L.tileLayer(url, { maxZoom: 19 }).addTo(map);
    };

    const handleLayerChange = (type: 'standard' | 'satellite' | 'dark') => {
        setMapLayer(type);
        if (mapInstanceRef.current) {
            updateTileLayer(mapInstanceRef.current, type);
        }
        setIsLayerMenuOpen(false);
    };

    const handleZoom = (dir: 'in' | 'out') => {
        if (!mapInstanceRef.current) return;
        if (dir === 'in') mapInstanceRef.current.zoomIn();
        else mapInstanceRef.current.zoomOut();
    };

    const handleRecenter = () => {
        if (mapInstanceRef.current) {
            mapInstanceRef.current.flyTo([location.lat, location.lng], 16, { duration: 1 });
        }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[100] flex flex-col bg-white dark:bg-[#0D1117] animate-fade-in-up">
            {/* Header */}
            <div className="flex items-center justify-between px-4 py-3 bg-white/90 dark:bg-[#161618]/90 backdrop-blur-md border-b border-gray-200 dark:border-gray-800 absolute top-0 left-0 right-0 z-20">
                <div className="flex items-center gap-3">
                    <div className="p-2 bg-red-100 dark:bg-red-900/30 rounded-full text-red-600 dark:text-red-400">
                        <MapPin className="w-5 h-5" />
                    </div>
                    <div>
                        <h2 className="text-sm font-bold text-gray-900 dark:text-white leading-tight">
                            {location.name || 'Pinned Location'}
                        </h2>
                        <p className="text-xs text-gray-500 dark:text-gray-400">
                            {location.lat.toFixed(5)}, {location.lng.toFixed(5)}
                        </p>
                    </div>
                </div>
                <button 
                    onClick={onClose}
                    className="p-2 rounded-full bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors"
                >
                    <X className="w-5 h-5" />
                </button>
            </div>

            {/* Map Container */}
            <div className="flex-1 relative bg-gray-100 dark:bg-black/20">
                <div ref={mapContainerRef} className="absolute inset-0 z-0" />

                {/* Controls Overlay */}
                <div className="absolute right-4 bottom-8 z-10 flex flex-col gap-3 pointer-events-none">

                     {/* External Link */}
                     <a 
                        href={`https://www.google.com/maps/search/?api=1&query=${location.lat},${location.lng}`} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="pointer-events-auto flex items-center justify-center w-12 h-12 bg-white dark:bg-[#1e1f22] rounded-xl shadow-lg border border-gray-200 dark:border-gray-700 text-blue-500 hover:scale-105 transition-transform"
                        title="Open in Google Maps"
                    >
                        <Navigation className="w-6 h-6" />
                    </a>

                    {/* Layer Switcher */}
                    <div className="pointer-events-auto relative flex flex-col items-end">
                            <button 
                            onClick={() => setIsLayerMenuOpen(!isLayerMenuOpen)}
                            className={`w-12 h-12 rounded-xl bg-white dark:bg-[#1e1f22] shadow-lg flex items-center justify-center border border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-800 transition-colors ${isLayerMenuOpen ? 'text-indigo-500' : 'text-gray-600 dark:text-gray-300'}`}
                        >
                            <Layers className="w-6 h-6" />
                        </button>

                        {isLayerMenuOpen && (
                            <div className="absolute bottom-full right-0 mb-3 p-2 bg-white dark:bg-[#1e1f22] rounded-2xl shadow-xl border border-gray-100 dark:border-gray-700 flex flex-col gap-1 w-36 animate-fade-in-up">
                                <button onClick={() => handleLayerChange('standard')} className={`flex items-center gap-3 px-3 py-2.5 rounded-xl text-xs font-bold ${mapLayer === 'standard' ? 'bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400' : 'text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-white/5'}`}>
                                    <MapPin className="w-4 h-4" /> Standard
                                </button>
                                <button onClick={() => handleLayerChange('satellite')} className={`flex items-center gap-3 px-3 py-2.5 rounded-xl text-xs font-bold ${mapLayer === 'satellite' ? 'bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400' : 'text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-white/5'}`}>
                                    <Globe className="w-4 h-4" /> Satellite
                                </button>
                                <button onClick={() => handleLayerChange('dark')} className={`flex items-center gap-3 px-3 py-2.5 rounded-xl text-xs font-bold ${mapLayer === 'dark' ? 'bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400' : 'text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-white/5'}`}>
                                    <Layers className="w-4 h-4" /> Dark
                                </button>
                            </div>
                        )}
                    </div>

                    {/* Zoom Controls */}
                    <div className="pointer-events-auto flex flex-col bg-white dark:bg-[#1e1f22] rounded-xl shadow-lg overflow-hidden border border-gray-200 dark:border-gray-700">
                        <button 
                            onClick={() => handleZoom('in')}
                            className="w-12 h-12 flex items-center justify-center text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800 active:bg-gray-200"
                        >
                            <Plus className="w-6 h-6" />
                        </button>
                        <div className="h-px bg-gray-200 dark:bg-gray-700 w-full" />
                        <button 
                            onClick={() => handleZoom('out')}
                            className="w-12 h-12 flex items-center justify-center text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800 active:bg-gray-200"
                        >
                            <Minus className="w-6 h-6" />
                        </button>
                    </div>

                    {/* Recenter Button */}
                    <button 
                        onClick={handleRecenter}
                        className="pointer-events-auto w-12 h-12 rounded-xl bg-white dark:bg-[#1e1f22] shadow-lg flex items-center justify-center text-gray-600 dark:text-gray-300 hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors border border-gray-200 dark:border-gray-700"
                    >
                        <Crosshair className="w-6 h-6" />
                    </button>
                </div>
            </div>
        </div>
    );
};

